import java.util.Scanner;

public class SecureBufferImplementation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a safe buffer size based on the length of user input
        int bufferSize = Math.min(userInput.length(), 10); // Choose a maximum buffer size

        char[] buffer = new char[bufferSize];

        // Copy user input into buffer with bounds checking
        userInput.getChars(0, bufferSize, buffer, 0);

        System.out.println("Buffer content: " + new String(buffer));
    }
}

